  \draw [->] (y) to node [below] {$v$} (C/0);
  \draw [->] (x) to node [left] {$f$} (y);
  \draw [->] (x) to node [sloped,above] {$u$} (C/0');
\end {tikzpicture}

\begin {tikzpicture}[diagram]
